<?php
$renderThread = function (array $comments, ?int $parentId = null, int $depth = 0) use (&$renderThread) {
    foreach ($comments as $comment) {
        $currentParent = isset($comment['parent_comment_id']) ? (int)$comment['parent_comment_id'] : 0;
        $expected = $parentId ?? 0;
        if ($currentParent !== $expected) {
            continue;
        }
        $badgeClass = ($comment['message_direction'] ?? '') === 'inbound' ? 'tag tag-success' : (($comment['message_direction'] ?? '') === 'outbound' ? 'tag' : 'tag tag-danger');
        echo '<div class="card" style="margin-top:8px;padding:8px;margin-left:' . (int)($depth * 22) . 'px">';
        echo '<div class="meta">' . e($comment['created_at']) . ' · ' . e((string)($comment['author_name'] ?? $comment['sender_name'] ?? 'System')) . ' · <span class="' . e($badgeClass) . '">' . e(ucfirst((string)($comment['message_direction'] ?? 'internal'))) . '</span> · ' . e(ucfirst((string)($comment['visibility_scope'] ?? 'internal'))) . '</div>';
        if (!empty($comment['sender_email'])) {
            echo '<div class="meta">' . e((string)$comment['sender_email']) . ($comment['message_source'] ? ' · ' . e((string)$comment['message_source']) : '') . '</div>';
        }
        echo '<div>' . nl2br(e($comment['comment_text'])) . '</div>';
        echo '</div>';
        $renderThread($comments, (int)$comment['id'], $depth + 1);
    }
};
?>
